{"file_path":"/home/user/workspace/lib/posts.ts","content":"import { unstable_cache } from 'next/cache';
import { revalidateTag } from 'next/cache';

export interface Post {
  id: number;
  title: string;
  body: string;
  createdAt: Date;
}

// In-memory store (a real app would use a database)
const store: Post[] = [
  { id: 1, title: 'Hello World', body: 'This is the first post.', createdAt: new Date() },
];

let nextId = 2;

const TAG = 'posts';

/** Fetch all posts, cached with the "posts" tag. */
export const getPosts = unstable_cache(
  async (): Promise<Post[]> => {
    // Simulate a slow data fetch to demonstrate cache behaviour
    await new Promise((r) => setTimeout(r, 500));
    return [...store].sort((a, b) => b.id - a.id);
  },
  ['posts-list'],
  { tags: [TAG] },
);

/** Insert a new post and immediately invalidate the cached list. */
export async function addPost(title: string, body: string): Promise<Post> {
  const post: Post = {
    id: nextId++,
    title,
    body,
    createdAt: new Date(),
  };
  store.unshift(post);

  // ⚠️ Next.js guarantees that after this call, the next invocation of any
  // cached function with the "posts" tag will re-execute and return fresh
  // data. The client will NOT receive stale cached content.
  revalidateTag(TAG);

  return post;
}
"}

