{"file_path":"/home/user/workspace/app/actions.ts","content":"'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title')?.toString().trim();
  const body = formData.get('body')?.toString().trim();

  if (!title || !body) {
    throw new Error('Title and body are required');
  }

  await addPost(title, body);

  // revalidateTag already fired inside addPost — but we demonstrate it here
  // explicitly so it's clear the action owns the cache-invalidation concern.
  revalidateTag('posts');

  redirect('/');
}
"}

