{"file_path":"/home/user/workspace/app/page.tsx","content":"import { getPosts } from '@/lib/posts';
import { createPost } from './actions';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: '2rem 1rem' }}>
      <h1>Posts</h1>

      <form action={createPost} style={{ marginBottom: '2rem', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
        <input
          name="title"
          placeholder="Title"
          required
          style={{ padding: '0.5rem', border: '1px solid #ccc', borderRadius: 4 }}
        />
        <textarea
          name="body"
          placeholder="Body"
          required
          rows={3}
          style={{ padding: '0.5rem', border: '1px solid #ccc', borderRadius: 4 }}
        />
        <button
          type="submit"
          style={{ padding: '0.5rem 1rem', background: '#0070f3', color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer' }}
        >
          Create Post
        </button>
      </form>

      {posts.length === 0 ? (
        <p>No posts yet.</p>
      ) : (
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {posts.map((post) => (
            <li key={post.id} style={{ marginBottom: '1.5rem', borderBottom: '1px solid #eee', paddingBottom: '1rem' }}>
              <h2 style={{ margin: '0 0 0.25rem' }}>{post.title}</h2>
              <p style={{ margin: 0, color: '#555' }}>{post.body}</p>
              <small style={{ color: '#999' }}>{post.createdAt.toLocaleString()}</small>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}
"}

